import { useState } from 'react';
import './App.css';
import SearchMovies from './SearchMovies';

function App() {
  const [favourites, seFavourites] = useState([])

  const addFavourite = (movie) => {
    seFavourites([...favourites, movie])
  }

  return (
    <div className="App">
      <SearchMovies addFavourite= {addFavourite} />
    </div>
  );
}

export default App;
